   224→/// Arguments for parade command
   225→#[derive(Debug)]
   226→pub struct jjrq_ParadeArgs {
   227→    pub file: std::path::PathBuf,
   228→    pub target: String,
   229→    pub full: bool,
   230→    pub remaining: bool,
   231→}
   232→
   233→/// Run the parade command - display comprehensive Heat status
   234→pub fn jjrq_run_parade(args: jjrq_ParadeArgs) -> i32 {
   235→    let gallops = match Gallops::jjrg_load(&args.file) {
   236→        Ok(g) => g,
   237→        Err(e) => {
   238→            eprintln!("jjx_parade: error: {}", e);
   239→            return 1;
   240→        }
   241→    };
   242→
   243→    // Determine target type by length
   244→    let target_str = args.target.strip_prefix('₢').or_else(|| args.target.strip_prefix('₣')).unwrap_or(&args.target);
   245→
   246→    if target_str.len() == 5 {
   247→        // Coronet - pace view
   248→        let coronet = match Coronet::jjrf_parse(&args.target) {
   249→            Ok(c) => c,
   250→            Err(e) => {
   251→                eprintln!("jjx_parade: error: {}", e);
   252→                return 1;
   253→            }
   254→        };
   255→
   256→        // Extract parent firemark
   257→        let firemark = coronet.jjrf_parent_firemark();
   258→        let heat_key = firemark.jjrf_display();
   259→        let heat = match gallops.heats.get(&heat_key) {
   260→            Some(h) => h,
   261→            None => {
   262→                eprintln!("jjx_parade: error: Heat '{}' not found", heat_key);
   263→                return 1;
   264→            }
   265→        };
   266→
   267→        // Find pace
   268→        let coronet_key = coronet.jjrf_display();
   269→        let pace = match heat.paces.get(&coronet_key) {
   270→            Some(p) => p,
   271→            None => {
   272→                eprintln!("jjx_parade: error: Pace '{}' not found in Heat '{}'", coronet_key, heat_key);
   273→                return 1;
   274→            }
   275→        };
   276→
   277→        // Display tack history - iterate in reverse order (oldest first)
   278→        if !pace.tacks.is_empty() {
   279→            // Print header with current state from tacks[0]
   280→            let current_tack = &pace.tacks[0];
   281→            println!("Pace: {} ({})", current_tack.silks, coronet_key);
   282→            println!("Heat: {}", heat_key);
   283→            println!();
   284→
   285→            // Iterate tacks in reverse order (oldest first)
   286→            for (index, tack) in pace.tacks.iter().rev().enumerate() {
   287→                let state_str = zjjrq_pace_state_str(&tack.state);
   288→                let commit_str = if tack.commit == "0000000" {
   289→                    "(no commit)".to_string()
   290→                } else {
   291→                    tack.commit.clone()
   292→                };
   293→
   294→                println!("[{}] {} ({})", index, state_str, commit_str);
   295→                println!("    Silks: {}", tack.silks);
   296→                if let Some(ref direction) = tack.direction {
   297→                    println!("    Direction: {}", direction);
   298→                }
   299→                println!();
   300→                // Indent spec text
   301→                for line in tack.text.lines() {
   302→                    println!("    {}", line);
   303→                }
   304→                println!();
   305→            }
   306→        }
   307→    } else if target_str.len() == 2 {
   308→        // Firemark - heat view
   309→        let firemark = match Firemark::jjrf_parse(&args.target) {
   310→            Ok(fm) => fm,
   311→            Err(e) => {
   312→                eprintln!("jjx_parade: error: {}", e);
   313→                return 1;
   314→            }
   315→        };
   316→
   317→        let heat_key = firemark.jjrf_display();
   318→        let heat = match gallops.heats.get(&heat_key) {
   319→            Some(h) => h,
   320→            None => {
   321→                eprintln!("jjx_parade: error: Heat '{}' not found", heat_key);
   322→                return 1;
   323→            }
   324→        };
   325→
   326→        if args.full {
   327→            // Full view: paddock + all specs
   328→            let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   329→                Ok(content) => content,
   330→                Err(e) => {
   331→                    eprintln!("jjx_parade: error reading paddock file '{}': {}", heat.paddock_file, e);
   332→                    return 1;
   333→                }
   334→            };
   335→
   336→            let status_str = match heat.status {
   337→                HeatStatus::Racing => "racing",
   338→                HeatStatus::Stabled => "stabled",
   339→                HeatStatus::Retired => "retired",
   340→            };
   341→
   342→            println!("Heat: {} ({})", heat.silks, heat_key);
   343→            println!("Status: {}", status_str);
   344→            println!("Created: {}", heat.creation_time);
   345→            println!();
   346→            println!("## Paddock");
   347→            println!();
   348→            println!("{}", paddock_content);
   349→            println!();
   350→            println!("## Paces");
   351→            println!();
   352→
   353→            for coronet_key in &heat.order {
   354→                if let Some(pace) = heat.paces.get(coronet_key) {
   355→                    if let Some(tack) = pace.tacks.first() {
   356→                        // Skip complete/abandoned if --remaining
   357→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
   358→                            continue;
   359→                        }
   360→                        let state_str = zjjrq_pace_state_str(&tack.state);
   361→                        println!("### {} ({}) [{}]", tack.silks, coronet_key, state_str);
   362→                        println!();
   363→                        println!("{}", tack.text);
   364→                        if let Some(ref direction) = tack.direction {
   365→                            println!();
   366→                            println!("**Direction:** {}", direction);
   367→                        }
   368→                        println!();
   369→                    }
   370→                }
   371→            }
   372→        } else {
   373→            // List view: numbered paces
   374→            // If --remaining, compute and print progress stats first
   375→            if args.remaining {
   376→                let mut complete_count = 0;
   377→                let mut abandoned_count = 0;
   378→                let mut rough_count = 0;
   379→                let mut bridled_count = 0;
   380→                for coronet_key in &heat.order {
   381→                    if let Some(pace) = heat.paces.get(coronet_key) {
   382→                        if let Some(tack) = pace.tacks.first() {
   383→                            match tack.state {
   384→                                PaceState::Complete => complete_count += 1,
   385→                                PaceState::Abandoned => abandoned_count += 1,
   386→                                PaceState::Rough => rough_count += 1,
   387→                                PaceState::Bridled => bridled_count += 1,
   388→                            }
   389→                        }
   390→                    }
   391→                }
   392→                let remaining_count = rough_count + bridled_count;
   393→                println!("# Progress: {} complete, {} abandoned, {} remaining ({} rough, {} bridled)",
   394→                    complete_count, abandoned_count, remaining_count, rough_count, bridled_count);
   395→            }
   396→
   397→            let mut num = 0;
   398→            for coronet_key in &heat.order {
   399→                if let Some(pace) = heat.paces.get(coronet_key) {
   400→                    if let Some(tack) = pace.tacks.first() {
   401→                        // Skip complete/abandoned if --remaining
   402→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
   403→                            continue;
   404→                        }
   405→                        num += 1;
   406→                        let state_str = zjjrq_pace_state_str(&tack.state);
   407→                        println!("{}. [{}] {} ({})", num, state_str, tack.silks, coronet_key);
   408→                    }
   409→                }
   410→            }
   411→        }
   412→    } else {
   413→        eprintln!("jjx_parade: error: target must be Firemark (2 chars) or Coronet (5 chars), got {} chars", target_str.len());
   414→        return 1;
   415→    }
   416→
   417→    0
   418→}
