   420→/// Helper to convert PaceState to display string
   421→fn zjjrq_pace_state_str(state: &PaceState) -> &'static str {
   422→    match state {
   423→        PaceState::Rough => "rough",
   424→        PaceState::Bridled => "bridled",
   425→        PaceState::Complete => "complete",
   426→        PaceState::Abandoned => "abandoned",
   427→    }
   428→}
