   430→// ============================================================================
   431→// Scout - Search across heats and paces with regex
   432→// ============================================================================
   433→
   434→/// Arguments for scout command
   435→#[derive(Debug)]
   436→pub struct jjrq_ScoutArgs {
   437→    pub file: std::path::PathBuf,
   438→    pub pattern: String,
   439→    pub actionable: bool,
   440→}
   441→
   442→/// Run the scout command - regex search across heats/paces
   443→pub fn jjrq_run_scout(args: jjrq_ScoutArgs) -> i32 {
   444→    use regex::RegexBuilder;
   445→
   446→    let gallops = match Gallops::jjrg_load(&args.file) {
   447→        Ok(g) => g,
   448→        Err(e) => {
   449→            eprintln!("jjx_scout: error: {}", e);
   450→            return 1;
   451→        }
   452→    };
   453→
   454→    // Build case-insensitive regex
   455→    let re = match RegexBuilder::new(&args.pattern)
   456→        .case_insensitive(true)
   457→        .build()
   458→    {
   459→        Ok(r) => r,
   460→        Err(e) => {
   461→            eprintln!("jjx_scout: error: invalid regex pattern: {}", e);
   462→            return 1;
   463→        }
   464→    };
   465→
   466→    // Track which heats have matches (for group headers)
   467→    let mut current_heat_key: Option<String> = None;
   468→
   469→    // Iterate all heats (racing, stabled, retired)
   470→    for (heat_key, heat) in &gallops.heats {
   471→        // Search each pace in order
   472→        for coronet_key in &heat.order {
   473→            if let Some(pace) = heat.paces.get(coronet_key) {
   474→                if let Some(tack) = pace.tacks.first() {
   475→                    // Apply actionable filter if requested
   476→                    if args.actionable {
   477→                        match tack.state {
   478→                            PaceState::Rough | PaceState::Bridled => {},
   479→                            _ => continue,
   480→                        }
   481→                    }
   482→
   483→                    // Search: silks, spec (tack text), direction, paddock content
   484→                    // Use owned strings to avoid lifetime issues
   485→                    let mut match_result: Option<(String, String)> = None;
   486→
   487→                    if re.is_match(&tack.silks) {
   488→                        match_result = Some(("silks".to_string(), tack.silks.clone()));
   489→                    } else if re.is_match(&tack.text) {
   490→                        match_result = Some(("spec".to_string(), tack.text.clone()));
   491→                    } else if let Some(ref direction) = tack.direction {
   492→                        if re.is_match(direction) {
   493→                            match_result = Some(("direction".to_string(), direction.clone()));
   494→                        }
   495→                    } else {
   496→                        // Search paddock content
   497→                        let paddock_path = std::path::Path::new(&heat.paddock_file);
   498→                        if let Ok(content) = fs::read_to_string(paddock_path) {
   499→                            if re.is_match(&content) {
   500→                                match_result = Some(("paddock".to_string(), content));
   501→                            }
   502→                        }
   503→                    }
   504→
   505→                    // If we found a match, output it
   506→                    if let Some((field_name, field_content)) = match_result {
   507→                        // Print heat header if this is a new heat
   508→                        if current_heat_key.as_ref() != Some(heat_key) {
   509→                            println!("{} {}", heat_key, heat.silks);
   510→                            current_heat_key = Some(heat_key.clone());
   511→                        }
   512→
   513→                        // Print pace line
   514→                        let state_str = zjjrq_pace_state_str(&tack.state);
   515→                        println!("  {} [{}] {}", coronet_key, state_str, tack.silks);
   516→
   517→                        // Print match line with context (extract ~60 chars around match)
   518→                        let match_excerpt = zjjrq_extract_match_context(&field_content, &re);
   519→                        println!("    {}: {}", field_name, match_excerpt);
   520→                    }
   521→                }
   522→            }
   523→        }
   524→    }
   525→
   526→    0
   527→}
   528→
   529→/// Extract context around the first regex match in content
   530→fn zjjrq_extract_match_context(content: &str, re: &regex::Regex) -> String {
   531→    if let Some(mat) = re.find(content) {
   532→        let start = mat.start();
   533→        let end = mat.end();
   534→
   535→        // Find context window (30 chars before, 30 chars after)
   536→        let context_before = 30;
   537→        let context_after = 30;
   538→
   539→        let window_start = start.saturating_sub(context_before);
   540→        let window_end = (end + context_after).min(content.len());
   541→
   542→        let mut excerpt = String::new();
   543→        if window_start > 0 {
   544→            excerpt.push_str("...");
   545→        }
   546→        excerpt.push_str(&content[window_start..window_end]);
   547→        if window_end < content.len() {
   548→            excerpt.push_str("...");
   549→        }
   550→
   551→        // Replace newlines with spaces for single-line display
   552→        excerpt.replace('\n', " ").replace('\r', "")
   553→    } else {
   554→        // Shouldn't happen, but fallback to truncated content
   555→        let truncated = content.chars().take(60).collect::<String>();
   556→        if content.len() > 60 {
   557→            format!("{}...", truncated)
   558→        } else {
   559→            truncated
   560→        }
   561→    }
   562→}
