   564→// ============================================================================
   565→// GetSpec - Get raw spec text for a Pace
   566→// ============================================================================
   567→
   568→/// Arguments for get_spec command
   569→#[derive(Debug)]
   570→pub struct jjrq_GetSpecArgs {
   571→    pub file: std::path::PathBuf,
   572→    pub coronet: Coronet,
   573→}
   574→
   575→/// Run the get_spec command - output raw spec text
   576→pub fn jjrq_run_get_spec(args: jjrq_GetSpecArgs) -> i32 {
   577→    let gallops = match Gallops::jjrg_load(&args.file) {
